sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.stats-section{

    display:flex;
    justify-content:center;
    gap:35px;
    flex-wrap:wrap;
    padding:80px 30px;
    background:linear-gradient(135deg,#f5f7fa,#eef3f8);

}

.stat-card{

    position:relative;
    overflow:hidden;
    width:240px;
    height:170px;
    background:#ffffff;
    border-radius:18px;
    display:flex;
    flex-direction:column;
    justify-content:center;
    align-items:center;
    text-align:center;
    box-shadow:0 10px 25px rgba(15,76,129,.10);
    border-top:6px solid #D4A017;
    transition:all .4s ease;

}

.stat-card::before{

    content:"";
    position:absolute;
    top:0;
    left:-120%;
    width:100%;
    height:100%;
    background:linear-gradient(
        90deg,
        transparent,
        rgba(255,255,255,.45),
        transparent
    );

    transition:.8s;

}

.stat-card:hover::before{

    left:120%;

}

.stat-card:hover{

    transform:translateY(-12px) scale(1.04);
    box-shadow:0 18px 35px rgba(15,76,129,.18);

}

.stat-card h2{

    font-size:52px;
    margin:0;
    color:#0F4C81;
    font-weight:700;
    transition:.35s;

}

.stat-card:hover h2{

    transform:scale(1.08);

}

.stat-card p{

    margin-top:15px;
    color:#666;
    font-size:18px;
    font-weight:600;
    letter-spacing:.3px;

}

@media(max-width:992px){

    .stats-section{

        gap:25px;

    }

    .stat-card{

        width:260px;

    }

}

@media(max-width:768px){

    .stats-section{

        flex-direction:column;
        align-items:center;
        padding:50px 20px;

    }

    .stat-card{

        width:100%;
        max-width:340px;

    }

}

sp_widget.script:
(function() {

    data.total = 0;
    data.pending = 0;
    data.approved = 0;
    data.completed = 0;

    var gr = new GlideRecord('x_1958816_enterp_0_network_request');
    gr.query();

    while (gr.next()) {

        data.total++;

        var state = gr.getDisplayValue('state');

        if (state == "Pending")
            data.pending++;

        if (state == "Approved")
            data.approved++;

        if (state == "Completed")
            data.completed++;

    }

})();
